template.code:
interface

uses
	System.SysUtils;

type
  TminhaClasse = class (TInterfacedObject, iMinhaClasse)
  private
	constructor Create;
	class var FInstance  : iMinhaClasse;
	class function New : iMinhaClasse; static;
  public	
    class property GetInstance : iMinhaClasse read New;
	destructor Destroy; override;
  end;

implementation

constructor TminhaClasse.Create;
begin

end;

destructor TminhaClasse.Destroy;
begin

  inherited;
end;

class function TminhaClasse.New: iMinhaClasse;
begin
  if Not Assigned(FInstance) then
    FInstance := TminhaClasse.Create;

  Result := FInstance;
end;

end.
